SELECT AVG(average_rating) AS avg_brewery_rating
FROM breweries
WHERE is_active = 1;

SELECT AVG(rating) AS average_rating
FROM ratings
WHERE brewery_id = (SELECT brewery_id FROM breweries WHERE name = 'NorthGate Brewing');

SELECT brewery_id, total_reviews
FROM breweries
ORDER BY total_reviews DESC;

SELECT name 
FROM breweries 
WHERE average_rating = (SELECT MAX(average_rating) FROM breweries);
